class KitchenStation implements Runnable {
    private final String name;
    private final int cookTimeMs;
    KitchenStation(String name, int ms) { this.name=name; cookTimeMs=ms; }

    @Override
    public void run() {
        System.out.printf("[%s] Starting (%.1fs)...%n", name, cookTimeMs/1000.0);
        try { Thread.sleep(cookTimeMs); } 
        catch (InterruptedException e) { Thread.currentThread().interrupt(); return; }
        System.out.printf("[%s] Done!%n", name);
    }
}

public class RestaurantKitchen {
    public static void main(String[] args) throws InterruptedException {
        long start = System.currentTimeMillis();

        Thread appetizer = new Thread(new KitchenStation("Appetizer",  500));
        Thread mainCourse= new Thread(new KitchenStation("Main Course",1000));
        Thread dessert   = new Thread(new KitchenStation("Dessert",     300));

        appetizer.start();
        mainCourse.start();
        dessert.start();

        System.out.println("Kitchen open — all stations cooking!");

        appetizer.join();
        mainCourse.join();
        dessert.join();

        long elapsed = System.currentTimeMillis() - start;
        System.out.printf("Meal complete in %dms (sequential: 1800ms)%n", elapsed);
    }
}

